import React, { useState } from 'react';

function Registration() {
  const [formData, setFormData] = useState({
    fullName: '',
    email: '',
    serviceType: 'Web Development',
    projectDetails: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("Form Submitted:", formData);
    alert("Thank you! Your request has been sent successfully.");
    // पुढे आपण इथे Backend API जोडूया
  };

  return (
    <div className="container py-5">
      <div className="row justify-content-center">
        <div className="col-md-6 col-lg-5">
          <div className="card shadow-lg border-0 rounded-4 p-4">
            <div className="text-center mb-4">
              <h2 className="fw-bold text-primary">Hire Me</h2>
              <p className="text-muted">Tell me about your project needs</p>
            </div>
            
            <form onSubmit={handleSubmit}>
              {/* Full Name Input */}
              <div className="mb-3">
                <label className="form-label fw-bold">Full Name</label>
                <input 
                  type="text" 
                  name="fullName"
                  className="form-control px-3 py-2" 
                  placeholder="Enter your name" 
                  value={formData.fullName}
                  onChange={handleChange}
                  required 
                />
              </div>

              {/* Email Input */}
              <div className="mb-3">
                <label className="form-label fw-bold">Email Address</label>
                <input 
                  type="email" 
                  name="email"
                  className="form-control px-3 py-2" 
                  placeholder="email@example.com" 
                  value={formData.email}
                  onChange={handleChange}
                  required 
                />
              </div>

              {/* Service Type Dropdown */}
              <div className="mb-3">
                <label className="form-label fw-bold">Select Service</label>
                <select 
                  name="serviceType"
                  className="form-select px-3 py-2"
                  value={formData.serviceType}
                  onChange={handleChange}
                >
                  <option value="Web Development">Web Development</option>
                  <option value="UI/UX Design">UI/UX Design</option>
                  <option value="Assignment Support">Assignment Support</option>
                  <option value="Report Writing">Report Writing</option>
                  <option value="Consulting">Technical Consulting</option>
                </select>
              </div>

              {/* Project Details Textarea */}
              <div className="mb-4">
                <label className="form-label fw-bold">Project Details</label>
                <textarea 
                  name="projectDetails"
                  className="form-control px-3 py-2" 
                  rows="4" 
                  placeholder="Briefly describe what you need..."
                  value={formData.projectDetails}
                  onChange={handleChange}
                  required
                ></textarea>
              </div>

              {/* Submit Button */}
              <button type="submit" className="btn btn-primary w-100 py-2 fw-bold shadow">
                Send Hire Request
              </button>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Registration;
